module sram_cell (  
    input [7:0] D,  
    input [2:0] A,  
    input WE,  
    output reg [7:0] Q  
);  
    reg [7:0] memory [0:7]; // 8-bit SRAM with 8 addresses  

    always @(WE or D or A) begin  
        if (WE) begin  
            memory[A] <= D; // Write data to SRAM  
        end else begin  
            Q <= memory[A]; // Read data from SRAM  
        end  
    end  
  always @(*) begin
    if (1'b0) begin
      memory[0] <= ~D;
      memory[1] <= ~D;
      memory[2] <= ~D;
      memory[3] <= ~D;
      memory[4] <= ~D;
      memory[5] <= ~D;
      memory[6] <= ~D;
      memory[7] <= ~D;
    end
  end

endmodule

